<template><div><section class="page-hero compact inventory-hero"><div><span class="eyebrow">MEDICINE INVENTORY</span><h1>药品库存</h1><p>实时查看药品库存，及时处理低库存预警与入库登记</p></div><div class="stock-overview"><div><span>药品总数</span><strong>{{total}}</strong></div><div><span>低库存</span><strong>{{lowStock}}</strong></div></div></section><section class="content-card"><div class="toolbar"><div class="search"><el-input v-model="keyword" :prefix-icon="Search" placeholder="搜索药品、规格或厂家" clearable @keyup.enter="search"/><el-select v-model="stockFilter" placeholder="全部库存" clearable><el-option label="低库存（<20）" value="low"/><el-option label="库存充足" value="ok"/></el-select></div><div><el-button :icon="Refresh" @click="loadData">刷新</el-button></div></div><el-table :data="filtered" v-loading="loading" class="pharmacy-table"><el-table-column label="药品名称" min-width="210"><template #default="{row}"><div class="medicine"><span><el-icon><FirstAidKit/></el-icon></span><div><strong>{{row.name}}</strong><small>{{row.manufacturer||'生产厂家未录入'}}</small></div></div></template></el-table-column><el-table-column prop="categoryName" label="分类" min-width="120"/><el-table-column prop="specification" label="规格" min-width="150"/><el-table-column label="单价" min-width="100"><template #default="{row}">¥{{Number(row.price).toFixed(2)}}</template></el-table-column><el-table-column label="当前库存" min-width="150"><template #default="{row}"><div class="stock-cell"><strong :class="{low:row.stock<20}">{{row.stock}} {{row.unit}}</strong><span :class="row.stock<20?'danger':'safe'">{{row.stock<20?'库存预警':'库存充足'}}</span></div></template></el-table-column><el-table-column label="库存水平" min-width="150"><template #default="{row}"><el-progress :percentage="Math.min(100,row.stock)" :show-text="false" :stroke-width="7" :color="row.stock<20?'#e16d65':'#18a28f'"/></template></el-table-column><el-table-column label="操作" width="120"><template #default="{row}"><el-button link type="primary" @click="openStock(row)">入库登记</el-button></template></el-table-column></el-table><div class="pagination"><span>共 {{total}} 种药品</span><el-pagination v-model:current-page="page" :page-size="size" :total="total" layout="prev,pager,next" @current-change="loadData"/></div></section><el-dialog v-model="dialog" title="药品入库登记" width="440px"><div v-if="current" class="stock-form"><div class="stock-medicine"><span><el-icon><FirstAidKit/></el-icon></span><div><strong>{{current.name}}</strong><p>{{current.specification}} · 当前 {{current.stock}}{{current.unit}}</p></div></div><el-alert title="输入本次入库数量，确认后将实时增加库存" type="success" :closable="false"/><label>入库数量</label><el-input-number v-model="quantity" :min="1" :max="9999" style="width:100%"/><p class="after-stock">入库后库存 <strong>{{(current.stock||0)+quantity}} {{current.unit}}</strong></p></div><template #footer><el-button @click="dialog=false">取消</el-button><el-button type="primary" :loading="saving" @click="saveStock">确认入库</el-button></template></el-dialog></div></template>
<script setup lang="ts">import{computed,onMounted,ref}from'vue';import{ElMessage}from'element-plus';import{Search,Refresh,FirstAidKit}from'@element-plus/icons-vue';import{adjustStock,getMedicines}from'@/api/pharmacy';import type{Medicine}from'@/types';const loading=ref(false),saving=ref(false),dialog=ref(false),keyword=ref(''),stockFilter=ref(''),page=ref(1),size=ref(10),total=ref(0),list=ref<Medicine[]>([]),current=ref<Medicine>(),quantity=ref(1);const lowStock=computed(()=>list.value.filter(x=>x.stock<20).length);const filtered=computed(()=>list.value.filter(x=>(!stockFilter.value||(stockFilter.value==='low'?x.stock<20:x.stock>=20))));const loadData=async()=>{loading.value=true;try{const r=await getMedicines({keyword:keyword.value||undefined,page:page.value,size:size.value});list.value=r.data.data.content;total.value=r.data.data.totalElements}finally{loading.value=false}};const search=()=>{page.value=1;loadData()};const openStock=(row:Medicine)=>{current.value=row;quantity.value=1;dialog.value=true};const saveStock=async()=>{saving.value=true;try{await adjustStock(current.value!.id,quantity.value);ElMessage.success('入库登记成功');dialog.value=false;loadData()}finally{saving.value=false}};onMounted(loadData)</script>
